using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Data.Entity;

namespace ProductReviewApp.Controllers
{
    public class ReviewController : Controller
    {
        private ProductDbContext db = new ProductDbContext();

        // GET: /Review/
        public ActionResult Index(int productId)
        {
            var reviews = db.Reviews.Where(r => r.ProductId == productId).ToList();
            return View(reviews);
        }

        [HttpPost]
        public ActionResult Create(Review review)
        {
            if (ModelState.IsValid)
            {
                review.UserId = User.Identity.GetUserId();
                db.Reviews.Add(review);
                db.SaveChanges();
                return RedirectToAction("Index", new { id = review.ProductId });
            }
            return View(review);
        }

        [HttpGet]
        public ActionResult Create(int productId)
        {
            return View(new Review());
        }

        // GET: /Review/Details/5
        public ActionResult Details(int? id)
        {
            if (id == null)
            {
                return new HttpStatusCodeResult(HttpStatusCode.BadRequest);
            }
            Review review = db.Reviews.Find(id);
            if (review == null)
            {
                return HttpNotFound();
            }
            return View(review);
        }

        // GET: /Review/Edit/5
        public ActionResult Edit(int? id)
        {
            if (id == null)
            {
                return new HttpStatusCodeResult(HttpStatusCode.BadRequest);
            }
            Review review = db.Reviews.Find(id);
            if (review == null)
            {
                return HttpNotFound();
            }
            return View(review);
        }

        // POST: /Review/Edit/5
        [HttpPost]
        public ActionResult Edit([Bind(Exclude = "ProductId")] Review review)
        {
            if (ModelState.IsValid)
            {
                db.Entry(review).State = EntityState.Modified;
                db.SaveChanges();
                return RedirectToAction("Index", new { id = review.ProductId });
            }
            return View(review);
        }

        // GET: /Review/Delete/5
        public ActionResult Delete(int? id)
        {
            if (id == null)
            {
                return new HttpStatusCodeResult(HttpStatusCode.BadRequest);
            }
            Review review = db.Reviews.Find(id);
            if (review == null)
            {
                return HttpNotFound();
            }
            return View(review);
        }

        // POST: /Review/Delete/5
        [HttpPost, ActionName("Delete")]
        public ActionResult DeleteConfirmed(int id)
        {
            Review review = db.Reviews.Find(id);
            db.Reviews.Remove(review);
            db.SaveChanges();
            return RedirectToAction("Index", new { id = review.ProductId });
        }
    }

    public class ProductDbContext : DbContext
    {
        public DbSet<Review> Reviews { get; set; }
        // other entity configurations...
    }

    public class Review
    {
        public int Id { get; set; }
        public string Text { get; set; }
        [AllowHtml]
        public string HtmlText { get; set; } // for storing HTML formatted text
        public int ProductId { get; set; }
        public int UserId { get; set; }

        // other properties...
    }
}